-- Batch 3: append 3 more modules (5-7) to each course body (sv/en/es).
-- Idempotent: skips a course whose first new module heading already exists.

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Prospektering på djupet"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "var och hur du hittar kvalificerade leads."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Leta i Google Maps, LinkedIn, branschregister och via tips. Kvalificera direkt: rätt storlek, tydligt behov och beslutsfattare. Hellre tio rätt företag än hundra slumpvisa."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Sök 'takläggare [stad]' på Google och notera vilka som saknas eller har dålig sajt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Bygg en lista på tio kvalificerade företag."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Förslag & offert"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "bygga ett tydligt förslag som leder till avtal."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Koppla varje del till behovet du hittade, håll det enkelt och visa ett tydligt pris och nästa steg. En offert ska vara lätt att säga ja till."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Du sa att ni tappar jobb till X – därför föreslår jag Startpaketet, så här ser det ut.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv ett förslag i tre punkter för en påhittad kund."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Uppföljning"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "följa upp tills du får ett besked."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "De flesta affärer kräver flera kontakter. Boka alltid nästa steg och följ upp offerter inom några dagar. Tystnad är inte ett nej."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Hej, hörde du tittat på förslaget – vilka tankar har du?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lägg en uppföljningsuppgift på varje öppen offert."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – Prospecting in depth"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "where and how to find qualified leads."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Search Google Maps, LinkedIn, industry registers and referrals. Qualify right away: right size, clear need and a decision maker. Better ten right companies than a hundred random ones."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Search 'roofer [city]' on Google and note who's missing or has a poor site."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Build a list of ten qualified companies."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – Proposal & quote"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to build a clear proposal that leads to an agreement."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Tie each part to the need you found, keep it simple and show a clear price and next step. A quote should be easy to say yes to."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You said you lose jobs to X – so I propose the Starter bundle, here's how it looks.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write a three-point proposal for an imagined customer."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Follow-up"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to follow up until you get an answer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Most deals need several contacts. Always book the next step and follow up on quotes within a few days. Silence isn't a no."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Hi, saw you looked at the proposal – what are your thoughts?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Add a follow-up task to every open quote."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Prospección en profundidad"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "dónde y cómo encontrar leads cualificados."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Busca en Google Maps, LinkedIn, registros del sector y referencias. Cualifica enseguida: tamaño adecuado, necesidad clara y decisor. Mejor diez empresas correctas que cien al azar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Busca 'instalador de tejados [ciudad]' en Google y anota quién falta o tiene mala web."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Crea una lista de diez empresas cualificadas."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – Propuesta y presupuesto"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a construir una propuesta clara que lleve a un acuerdo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Conecta cada parte con la necesidad detectada, mantenlo simple y muestra un precio claro y el siguiente paso. Un presupuesto debe ser fácil de aceptar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Dijiste que pierdes trabajos frente a X, por eso propongo el Paquete inicial, así queda.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe una propuesta de tres puntos para un cliente imaginario."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Seguimiento"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a hacer seguimiento hasta obtener una respuesta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "La mayoría de ventas requieren varios contactos. Agenda siempre el siguiente paso y haz seguimiento de los presupuestos en pocos días. El silencio no es un no."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Hola, vi que miraste la propuesta, ¿qué te parece?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Añade una tarea de seguimiento a cada presupuesto abierto."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Grundkurs: Sälj från A till Ö'
  AND ti.body::text NOT LIKE '%Modul 5 – Prospektering på djupet%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – De fyra frågetyperna"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "strukturera dina frågor."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Situationsfrågor (läget idag), problemfrågor (vad skaver), konsekvensfrågor (vad det kostar) och nyttofrågor (värdet av en lösning). Konsekvensfrågorna gör behovet känsligt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Vad kostar det er att tappa de där förfrågningarna varje månad?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv en fråga av varje typ inför nästa möte."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Tystnadens kraft"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "använda pauser medvetet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Efter en bra fråga – var tyst. Tystnad känns obekvämt men får kunden att fylla i och tänka högt. Avbryt inte."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Ställ en konsekvensfråga och räkna tyst till tre innan du säger något mer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Öva på att pausera tre sekunder efter varje fråga."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Sammanfatta & få ja"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "stänga behovsanalysen innan pitchen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Sammanfatta vad du hört och be kunden bekräfta. Ett 'ja, precis' innan pitchen gör att förslaget landar som en lösning, inte en gissning."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Så om jag förstått rätt är X viktigast och Y skaver mest – stämmer det?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Avsluta nästa behovsanalys med en sammanfattning."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – The four question types"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to structure your questions."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Situation questions (the current state), problem questions (what chafes), implication questions (what it costs) and need-payoff questions (the value of a solution). Implication questions make the need urgent."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"What does it cost you to lose those enquiries every month?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write one question of each type before your next meeting."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – The power of silence"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to use pauses deliberately."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "After a good question – stay silent. Silence feels uncomfortable but makes the customer fill in and think out loud. Don't interrupt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Ask an implication question and count to three silently before saying more."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Practise pausing three seconds after each question."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Summarise & get a yes"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to close the needs analysis before the pitch."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Summarise what you heard and ask the customer to confirm. A 'yes, exactly' before the pitch makes the proposal land as a solution, not a guess."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"So if I understood right, X matters most and Y chafes most – correct?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "End your next needs analysis with a summary."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Los cuatro tipos de pregunta"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a estructurar tus preguntas."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Preguntas de situación (el estado actual), de problema (qué molesta), de implicación (qué cuesta) y de beneficio (el valor de una solución). Las de implicación hacen urgente la necesidad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Cuánto os cuesta perder esas solicitudes cada mes?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe una pregunta de cada tipo antes de tu próxima reunión."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – El poder del silencio"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a usar las pausas a propósito."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Tras una buena pregunta, guarda silencio. Incomoda, pero hace que el cliente rellene y piense en voz alta. No interrumpas."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Haz una pregunta de implicación y cuenta hasta tres en silencio antes de seguir."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Practica pausar tres segundos tras cada pregunta."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Resume y consigue un sí"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a cerrar el análisis antes del pitch."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Resume lo que oíste y pide al cliente que lo confirme. Un 'sí, exacto' antes del pitch hace que la propuesta caiga como solución, no como suposición."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Si entendí bien, X es lo más importante e Y lo que más molesta, ¿correcto?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Termina tu próximo análisis con un resumen."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Behovsanalys & frågeteknik'
  AND ti.body::text NOT LIKE '%Modul 5 – De fyra frågetyperna%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Förebygg invändningar"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "ta udden av invändningar innan de kommer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ta upp pris och vanliga farhågor proaktivt, så känns de mindre laddade. Den som adresserar elefanten i rummet bygger förtroende."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Många undrar om det är värt pengarna – låt mig visa hur det betalar sig.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lista tre farhågor du kan ta upp proaktivt."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – De vanligaste invändningarna"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "känna igen och bemöta de åtta vanliga."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "För dyrt, har redan hemsida, gör det själva, ingen tid, skicka info, nöjd med leverantör, funkar SEO/GEO, måste tänka på det. Kan du svaren i sömnen tappar du aldrig tempo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Dra en kollega och låt hen skjuta invändningar – svara direkt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv ett kort svar på var och en av de åtta."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Förhandlingsteknik"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "förhandla utan att tappa värde."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ankra med ditt ordinarie pris, ge aldrig utan att få något tillbaka och våga vara tyst efter ett bud. Den som pratar först efter ett bud förlorar ofta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Jag kan lösa det priset om vi skriver ett längre avtal – funkar det?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Bestäm i förväg vad du kan ge och vad du vill ha tillbaka."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – Prevent objections"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to take the edge off objections before they arise."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Raise price and common concerns proactively, so they feel less charged. Addressing the elephant in the room builds trust."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Many wonder if it's worth the money – let me show how it pays off.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "List three concerns you can raise proactively."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – The most common objections"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to recognise and meet the eight common ones."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Too expensive, already have a site, do it themselves, no time, send info, happy with supplier, does SEO/GEO work, need to think. Know the answers cold and you never lose momentum."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Grab a colleague and have them fire objections – answer instantly."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write a short reply to each of the eight."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Negotiation technique"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to negotiate without losing value."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Anchor with your standard price, never give without getting something back, and dare to be silent after an offer. Whoever speaks first after an offer often loses."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"I can do that price if we sign a longer contract – works?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Decide in advance what you can give and what you want back."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Previene objeciones"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a quitar fuerza a las objeciones antes de que surjan."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Plantea el precio y las preocupaciones comunes de forma proactiva, así pesan menos. Quien aborda el elefante en la sala genera confianza."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Muchos se preguntan si vale la pena, déjame mostrar cómo se amortiza.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Enumera tres preocupaciones que puedes plantear proactivamente."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – Las objeciones más comunes"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a reconocer y responder las ocho habituales."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Demasiado caro, ya tienen web, lo hacen ellos, sin tiempo, envía info, contentos con su proveedor, ¿funciona SEO/GEO?, tienen que pensarlo. Sabértelas de memoria evita perder ritmo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Pide a un compañero que dispare objeciones y responde al instante."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe una respuesta corta a cada una de las ocho."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Técnica de negociación"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a negociar sin perder valor."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ancla con tu precio estándar, nunca cedas sin recibir algo a cambio y atrévete a callar tras una oferta. Quien habla primero tras una oferta suele perder."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Puedo hacer ese precio si firmamos un contrato más largo, ¿te va?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Decide de antemano qué puedes ceder y qué quieres a cambio."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Invändningshantering & förhandling'
  AND ti.body::text NOT LIKE '%Modul 5 – Förebygg invändningar%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Förbered samtalet"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "komma förberedd till varje pass."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ha en lista, ditt manus och ett tydligt mål framför dig. Ring i fokuserade pass och stör inte med annat. Förberedelse ger självförtroende."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Sätt ett mål: 20 samtal och 2 bokade möten på en timme."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Förbered en ringlista på 20 företag inför nästa pass."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Ta dig förbi gatekeepern"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "hantera växel och assistenter artigt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Var trevlig, kort och rak. Be om personen vid namn om du kan, och behandla gatekeepern som en allierad, inte ett hinder."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Hej, kan du hjälpa mig till den som ansvarar för er hemsida?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv en mening för att artigt be att bli kopplad."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Mät och förbättra"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "följa upp dina egna siffror."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Räkna samtal, kontakter och bokade möten. När du vet din konverteringsgrad vet du också hur många samtal ett möte kostar – och kan förbättra delarna."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "20 samtal → 5 samtal med rätt person → 2 möten = din tratt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Logga dagens samtal och möten och räkna ut din boknings­grad."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – Prepare the call"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to come prepared to every session."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Have a list, your script and a clear goal in front of you. Call in focused blocks and don't multitask. Preparation gives confidence."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Set a goal: 20 calls and 2 booked meetings in an hour."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Prepare a call list of 20 companies for your next session."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – Get past the gatekeeper"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to handle switchboards and assistants politely."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Be friendly, short and direct. Ask for the person by name if you can, and treat the gatekeeper as an ally, not an obstacle."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Hi, can you help me reach whoever's responsible for your website?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write a line to politely ask to be put through."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Measure and improve"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to track your own numbers."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Count calls, contacts and booked meetings. Once you know your conversion rate you know how many calls a meeting costs – and can improve the parts."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "20 calls → 5 calls with the right person → 2 meetings = your funnel."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Log today's calls and meetings and calculate your booking rate."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Prepara la llamada"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a llegar preparado a cada sesión."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ten una lista, tu guion y un objetivo claro delante. Llama en bloques enfocados y no hagas varias cosas a la vez. La preparación da confianza."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Fíjate una meta: 20 llamadas y 2 reuniones agendadas en una hora."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Prepara una lista de 20 empresas para tu próxima sesión."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – Pasa al gatekeeper"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a tratar con centralitas y asistentes con cortesía."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Sé amable, breve y directo. Pide a la persona por su nombre si puedes y trata al gatekeeper como un aliado, no un obstáculo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Hola, ¿puedes ayudarme a llegar al responsable de vuestra web?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe una frase para pedir amablemente que te pasen."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Mide y mejora"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a seguir tus propios números."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Cuenta llamadas, contactos y reuniones agendadas. Cuando sabes tu tasa de conversión sabes cuántas llamadas cuesta una reunión, y puedes mejorar las partes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "20 llamadas → 5 con la persona correcta → 2 reuniones = tu embudo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Registra las llamadas y reuniones de hoy y calcula tu tasa de agenda."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Mötesbokning & kalla samtal'
  AND ti.body::text NOT LIKE '%Modul 5 – Förbered samtalet%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Nyckelord"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "hitta vad kunderna faktiskt söker på."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Utgå från kundens språk, inte ditt eget. Kombinera tjänst och plats ('takläggare Göteborg') och leta efter ord med köpavsikt. Rätt nyckelord styr hela SEO-arbetet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "'pris takbyte' visar köpavsikt; 'vad är ett tak' gör det inte."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lista fem nyckelord en kund i din bransch skulle googla."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Teknisk SEO"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "förstå grunderna som påverkar ranking."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Fart, mobilanpassning, säker anslutning (HTTPS) och tydlig struktur. Google belönar sajter som är snabba och lätta att förstå – det är delvis därför vi bygger i Astro/React."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "En sajt som laddar på 1 sekund slår en som tar 5."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Testa en kunds sajt i Googles PageSpeed och notera betyget."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – GEO i praktiken"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "optimera för att nämnas av AI."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "AI väljer källor som är tydliga, trovärdiga och välstrukturerade. Tydligt innehåll, vanliga frågor och omnämnanden på andra sajter ökar chansen att bli rekommenderad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Fråga ChatGPT 'bästa webbyrå i [stad]' och se vilka som nämns."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv tre vanliga frågor en kunds sajt borde besvara."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – Keywords"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to find what customers actually search for."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start from the customer's language, not your own. Combine service and place ('roofer Gothenburg') and look for words with buying intent. The right keywords steer all SEO work."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "'price roof replacement' shows buying intent; 'what is a roof' doesn't."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "List five keywords a customer in your industry would google."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – Technical SEO"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to understand the basics that affect ranking."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Speed, mobile-friendliness, secure connection (HTTPS) and clear structure. Google rewards sites that are fast and easy to understand – partly why we build in Astro/React."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "A site that loads in 1 second beats one that takes 5."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Test a customer's site in Google PageSpeed and note the score."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – GEO in practice"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to optimise for being mentioned by AI."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "AI picks sources that are clear, credible and well-structured. Clear content, FAQs and mentions on other sites raise the chance of being recommended."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Ask ChatGPT 'best web agency in [city]' and see who's mentioned."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write three FAQs a customer's site should answer."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Palabras clave"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a encontrar lo que los clientes buscan de verdad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Parte del lenguaje del cliente, no del tuyo. Combina servicio y lugar ('instalador de tejados Gotemburgo') y busca palabras con intención de compra. Las palabras clave guían todo el SEO."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "'precio cambio de tejado' muestra intención; 'qué es un tejado' no."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Lista cinco palabras que un cliente de tu sector buscaría."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – SEO técnico"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a entender lo básico que afecta al ranking."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Velocidad, adaptación a móvil, conexión segura (HTTPS) y estructura clara. Google premia los sitios rápidos y fáciles de entender, en parte por eso construimos en Astro/React."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Un sitio que carga en 1 segundo supera a uno que tarda 5."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Prueba la web de un cliente en Google PageSpeed y anota la nota."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – GEO en la práctica"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a optimizar para ser mencionado por la IA."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "La IA elige fuentes claras, creíbles y bien estructuradas. Contenido claro, preguntas frecuentes y menciones en otros sitios aumentan la probabilidad de ser recomendado."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Pregunta a ChatGPT 'mejor agencia web en [ciudad]' y mira a quién menciona."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe tres preguntas frecuentes que la web de un cliente debería responder."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Digital spetskunskap: SEO & GEO'
  AND ti.body::text NOT LIKE '%Modul 5 – Nyckelord%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Astro eller React"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "välja rätt teknik för kunden."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Statisk sajt i Astro för verksamheter som mest presenterar (hantverk, restaurang, konsult). Dynamiskt i React när det behövs inloggning, bokning eller realtidsdata. Behovet styr tekniken."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Bokningssystem → React. Snygg broschyrsajt → Astro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Para ihop tre kunder med rätt teknikval."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Kombinationspaket"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "sälja helheter istället för delar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Startpaket (hemsida + SEO), Tillväxtpaket (hemsida + SEO + GEO) och MVP-paket (MVP + designpartner) höjer ordervärdet och ger kunden en helhet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Vill ni synas och konvertera från dag ett? Tillväxtpaketet löser båda.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Föreslå ett kombinationspaket för en påhittad kund."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Räkna hem värdet"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "motivera priset med ROI."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Sätt priset i relation till vad en kund är värd. En sajt för 18 000 kr som drar in två kunder i månaden betalar sig snabbt. Sälj investering, inte kostnad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Vad är en ny kund värd? Då ser ni hur snabbt sajten betalar sig.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Räkna ut återbetalningstiden för ett paket åt en kund."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – Astro or React"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to choose the right tech for the customer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Static site in Astro for businesses that mostly present (trades, restaurant, consultant). Dynamic in React when login, booking or real-time data is needed. The need drives the tech."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Booking system → React. A sharp brochure site → Astro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Match three customers with the right tech choice."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – Combination bundles"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to sell wholes instead of parts."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Starter bundle (website + SEO), Growth bundle (website + SEO + GEO) and MVP bundle (MVP + design partner) raise the order value and give the customer a whole."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Want to be seen and convert from day one? The Growth bundle does both.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Propose a combination bundle for an imagined customer."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Make the value add up"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to justify the price with ROI."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Set the price against what a customer is worth. A SEK 18,000 site that brings in two customers a month pays off fast. Sell investment, not cost."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"What is a new customer worth? Then you see how fast the site pays off.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Calculate the payback time of a package for a customer."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Astro o React"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a elegir la tecnología adecuada para el cliente."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Sitio estático en Astro para negocios que sobre todo presentan (oficios, restaurante, consultor). Dinámico en React cuando hace falta login, reservas o datos en tiempo real. La necesidad guía la tecnología."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Sistema de reservas → React. Web folleto atractiva → Astro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Empareja tres clientes con la elección técnica adecuada."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – Paquetes combinados"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a vender conjuntos en vez de partes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Paquete inicial (web + SEO), Paquete de crecimiento (web + SEO + GEO) y Paquete MVP (MVP + socio de diseño) suben el valor del pedido y dan al cliente un conjunto."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Queréis aparecer y convertir desde el primer día? El Paquete de crecimiento hace ambas.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Propón un paquete combinado para un cliente imaginario."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Haz que el valor cuadre"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a justificar el precio con el ROI."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Pon el precio frente a lo que vale un cliente. Una web de 18 000 SEK que trae dos clientes al mes se amortiza rápido. Vende inversión, no coste."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Cuánto vale un cliente nuevo? Así ves lo rápido que se paga la web.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Calcula el periodo de amortización de un paquete para un cliente."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Produktmästaren'
  AND ti.body::text NOT LIKE '%Modul 5 – Astro eller React%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Hjälteresan i sälj"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "göra kunden till hjälten."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Kunden är hjälten, du är guiden. Berätta om var de är nu, vart de vill, och hur du hjälper dem dit. Ställ aldrig dig själv i centrum."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Ni vill nå dit – så här tar vi er dit, steg för steg.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv en mening där kunden är hjälten och du guiden."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Sociala bevis"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "använda case och omdömen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Människor litar på andra människor. Ett kort kundcase, ett omdöme eller en siffra övertygar mer än dina egna påståenden."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"En liknande kund fördubblade sina förfrågningar på tre månader.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Samla tre konkreta bevis du kan använda."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Ord som säljer"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "välja rätt språk i pitchen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Konkreta, enkla ord slår jargong. Säg 'fler kunder' istället för 'ökad konvertering'. Undvik svepande superlativ – var specifik istället."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "'Ni får fler förfrågningar' slår 'vi maximerar er digitala potential'."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv om en jargong-mening till enkelt språk."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – The hero's journey in sales"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to make the customer the hero."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "The customer is the hero, you are the guide. Tell where they are now, where they want to go, and how you help them get there. Never put yourself at the centre."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You want to get there – here's how we take you there, step by step.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write a sentence where the customer is the hero and you the guide."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – Social proof"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to use cases and testimonials."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "People trust other people. A short customer case, a testimonial or a number convinces more than your own claims."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"A similar customer doubled their enquiries in three months.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Collect three concrete proofs you can use."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Words that sell"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to choose the right language in the pitch."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Concrete, simple words beat jargon. Say 'more customers' instead of 'increased conversion'. Avoid sweeping superlatives – be specific instead."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "'You get more enquiries' beats 'we maximise your digital potential'."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Rewrite a jargon sentence into plain language."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – El viaje del héroe en ventas"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a convertir al cliente en el héroe."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "El cliente es el héroe, tú eres el guía. Cuenta dónde están, a dónde quieren ir y cómo les ayudas a llegar. Nunca te pongas en el centro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Queréis llegar ahí: así os llevamos, paso a paso.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe una frase donde el cliente sea el héroe y tú el guía."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – Prueba social"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a usar casos y testimonios."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "La gente confía en otras personas. Un caso breve, un testimonio o un número convencen más que tus propias afirmaciones."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Un cliente parecido duplicó sus solicitudes en tres meses.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Reúne tres pruebas concretas que puedas usar."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Palabras que venden"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a elegir el lenguaje adecuado en el pitch."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Las palabras concretas y simples superan la jerga. Di 'más clientes' en vez de 'mayor conversión'. Evita superlativos vagos, sé específico."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "'Tendréis más solicitudes' supera a 'maximizamos vuestro potencial digital'."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Reescribe una frase con jerga en lenguaje sencillo."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'Storytelling & pitch'
  AND ti.body::text NOT LIKE '%Modul 5 – Hjälteresan i sälj%';

UPDATE public.training_items ti
SET body    = jsonb_set(ti.body,    '{content}', (ti.body->'content')    || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 5 – Pipeline-stadier"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "flytta affärer framåt steg för steg."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "En affär rör sig genom stadier: ny lead, kontaktad, möte bokat, offert skickad, vunnen eller förlorad. Varje lead ska alltid ha ett aktuellt stadium och ett nästa steg."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "En offert som legat i 'skickad' i två veckor behöver en uppföljning."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Sätt rätt stadium på varje aktiv lead i din pipeline."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 6 – Daglig rutin"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "jobba systematiskt varje dag."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Börja dagen med att kolla dagens uppgifter och möten, jobba av dem och boka nästa steg. En enkel daglig rutin gör att inget faller mellan stolarna."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Morgon: kolla uppgifter. Dagen: ring och boka. Kväll: logga och planera."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv din egen tre-stegs dagsrutin i CRM:t."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 7 – Rapporter & nyckeltal"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "mäta det som driver resultat."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Följ samtal, bokade möten, skickade offerter och vunna affärer. Siffrorna visar var det stockar sig och vad du ska göra mer av."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Få möten men inga avslut? Då är det pitchen eller offerten som skaver."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lista de fyra nyckeltal du vill följa varje vecka."}]}]$j$::jsonb),
    body_en = jsonb_set(ti.body_en, '{content}', (ti.body_en->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 5 – Pipeline stages"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to move deals forward step by step."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "A deal moves through stages: new lead, contacted, meeting booked, quote sent, won or lost. Every lead should always have a current stage and a next step."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "A quote stuck in 'sent' for two weeks needs a follow-up."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Set the right stage on every active lead in your pipeline."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 6 – Daily routine"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to work systematically every day."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Start the day by checking today's tasks and meetings, work through them and book the next step. A simple daily routine keeps things from slipping through the cracks."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Morning: check tasks. Day: call and book. Evening: log and plan."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write your own three-step daily routine in the CRM."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 7 – Reports & metrics"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to measure what drives results."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Track calls, booked meetings, quotes sent and deals won. The numbers show where things get stuck and what to do more of."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Lots of meetings but no closes? Then the pitch or quote is the issue."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "List the four metrics you want to track every week."}]}]$j$::jsonb),
    body_es = jsonb_set(ti.body_es, '{content}', (ti.body_es->'content') || $j$[{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 5 – Etapas del pipeline"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a mover ventas hacia adelante paso a paso."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Una venta avanza por etapas: lead nuevo, contactado, reunión agendada, presupuesto enviado, ganada o perdida. Cada lead debe tener siempre una etapa actual y un siguiente paso."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Un presupuesto en 'enviado' dos semanas necesita seguimiento."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Pon la etapa correcta a cada lead activo de tu pipeline."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 6 – Rutina diaria"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a trabajar de forma sistemática cada día."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Empieza el día revisando tareas y reuniones, resuélvelas y agenda el siguiente paso. Una rutina diaria sencilla evita que algo se pierda."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Mañana: revisa tareas. Día: llama y agenda. Tarde: registra y planifica."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe tu propia rutina diaria de tres pasos en el CRM."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 7 – Informes y métricas"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a medir lo que impulsa resultados."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Sigue llamadas, reuniones agendadas, presupuestos enviados y ventas ganadas. Los números muestran dónde se atasca y qué hacer más."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "¿Muchas reuniones pero sin cierres? Entonces el pitch o el presupuesto falla."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Enumera las cuatro métricas que quieres seguir cada semana."}]}]$j$::jsonb)
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'kurser'
  AND ti.title = 'CRM-mästaren'
  AND ti.body::text NOT LIKE '%Modul 5 – Pipeline-stadier%';
